INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'overview', 'Overview > Full Name: National Institute of Technology Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'overview', 'Overview > Location: Langol, Imphal-795004, Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'overview', 'Overview > Phone: (0385) 2449312/2059391.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'overview', 'Overview > Email: nitmanipur@yahoo.in, Website: www.nitmanipur.ac.in.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'overview', 'Overview > Languages spoken: Official language is Meitei (Manipuri/Meiteilon). Most people also speak Hindi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'overview', 'Overview > Climate: Moderate, subtropical monsoonal climate.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'transport', 'Transport > Airport: Imphal Airport is 9.1 km from NIT Manipur campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'transport', 'Transport > Railway: Dimapur Railway Station is 200-205 km from NIT Manipur campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'transport', 'Transport > Bus: Bus from Dimapur to Imphal costs Rs 700. Winger/bus available from Dimapur to Imphal.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'transport', 'Transport > Train Route: Vivek Dibrugarh Express runs from Rajahmundry to Dimapur, then take winger/bus to Imphal.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'restaurants', 'Restaurants > Nearby: Handi Story (Andhra style restaurant, 5.6 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'restaurants', 'Restaurants > Nearby: Many small local restaurants are available near NIT Manipur campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'nearby_places', 'Nearby Places > Tourist: Loktak Lake (48 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'nearby_places', 'Nearby Places > Tourist: Keibul Lamjao National Park (55 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'nearby_places', 'Nearby Places > Tourist: Ukhrul hill station (83 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'nearby_places', 'Nearby Places > Shopping: Zudio (5.7 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'nearby_places', 'Nearby Places > Shopping: Trends (5.5 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'nearby_places', 'Nearby Places > Shopping: Mamcy Mall (7.0 km from campus).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys: H01 - inside campus, for 3rd and 4th year students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys: H02 - inside campus, for 3rd and 4th year students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys: H03 - inside campus, for 2nd year students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys: NIT Manipur Private Boys Hostel 05 - 1.5 km from campus, for 1st year students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys: PhD Hostel H04 - 1 km from campus, for MTech and PhD students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys Room Types: Big room (5 students per room) and Small room (3 students per room).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Boys Summary: 5 boys hostels total. H01, H02, H03 are inside campus. Hostel 05 is 1.5 km away for 1st years. PhD Hostel H04 is 1 km away for MTech/PhD.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Girls: NIT Manipur Takyel Girls Hostel - for 1st and 2nd year girls, 4-6 km from airport, 3 km from bus stand.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Girls: NIT Manipur Girls Hostel near campus - walking distance from campus, for 3rd and 4th year girls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'hostels', 'Hostels > Girls Summary: 2 girls hostels at NIT Manipur. Takyel hostel for juniors, near-campus hostel for seniors.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Assignment: H02 and H03 share the same mess. H01 has a separate mess. Hostel 05 (1st years) has a separate mess. PhD hostel has a separate mess. All hostels follow the same menu.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Timings: Breakfast 7 AM - 9 AM, Lunch 12 PM - 2 PM, Snacks 5 PM - 6 PM, Dinner 7 PM - 9 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Sunday Breakfast: Aloo Paratha, Tea, Tomato Sauce.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Sunday Lunch: Rice, Dal, Sambar, Broccoli/Pumpkin, Salad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Sunday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Sunday Dinner: Rice, Roti, Dal, Chicken/Paneer.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Monday Breakfast: Puri, Sabji, Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Monday Lunch: Rice, Roti, Bengan, Dal, Uti, Ametpa.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Monday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Monday Dinner: Rice, Dal, Fish Curry/Kabuli Chana.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Tuesday Breakfast: Chowmein, Sauce, Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Tuesday Lunch: Rice, Roti, Dal, Cauliflower, Ironba.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Tuesday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Tuesday Dinner: Rice, Roti, Rajma, Salad Sweet.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Wednesday Breakfast: Plain Paratha, Black Channa, Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Wednesday Lunch: Rice, Roti, Dal, Sambar, Giya Papad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Wednesday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Wednesday Dinner: Rice, Roti, Dal, Chicken Curry/Paneer.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Thursday Breakfast: Fried Rice, Sauce, Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Thursday Lunch: Rice, Roti, Aloo Soyabean, Ironba, Pickle.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Thursday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Thursday Dinner: Rice, Roti, Dal, Egg Curry/Cauliflower.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Friday Breakfast: Puri, Sabji, Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Friday Lunch: Rice, Roti, Dal, Aloo Gobi, Salad.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Friday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Friday Dinner: Rice, Dal, Paneer.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Saturday Breakfast: Bread, Banana, Jam, Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Saturday Lunch: Rice, Roti, Dal, Squash Uti, Ametpa.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Saturday Snacks: Milk Tea.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Saturday Dinner: Rice, Roti, Dal, Egg Curry/Aloo Peanut.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Notes: Menu includes local Manipuri items such as Ironba, Ametpa, and Uti. Chicken is served on Sunday and Wednesday. Fish is served on Monday. Egg is served on Thursday and Saturday.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'mess', 'Mess > Cuisine: Mix of North Indian staples (roti, dal, rice) with local Manipuri dishes (Ironba, Ametpa, Uti) and some Chinese-influenced items (chowmein, fried rice). Non-veg options include chicken, fish, and egg on specific days.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fee_structure', 'Fee Structure > Program: B.Tech (2016 batch onwards).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fee_structure', 'Fee Structure > Academic Fees per semester: Tuition Fee Rs 62,500, Alumni Fee Rs 1,000, Institute Development Fund Rs 1,000, Medical Insurance and GPD Rs 600, Library Fee Rs 500, Exam Fee Rs 500, Student Aid Rs 500, Grade Card Rs 500, Steno ID Fee Rs 100.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fee_structure', 'Fee Structure > One-time fees (1st semester only): Admission Fee Rs 1,000, Mess Caution Deposit Rs 7,500 (refundable).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fee_structure', 'Fee Structure > Hostel Fees per semester: Hostel Rent Rs 2,500-3,500, Establishment/Amenities/Hostel Maintenance Rs 2,500, Electricity Rs 1,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fee_structure', 'Fee Structure > Fee Waivers: SC/ST/PH students get complete tuition fee exemption. Family income below Rs 1 lakh gets full tuition remission. Family income Rs 1-5 lakh gets 2/3rd tuition remission.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fee_structure', 'Fee Structure > SC/ST students under government scholarship: Tuition fee to be borne by Ministry of Tribal/Social Development.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'wifi', 'WiFi > Hostel WiFi and college WiFi are both available at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'wifi', 'WiFi > Mobile Networks: Both Airtel and Jio 5G have good coverage at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'attendance', 'Attendance > 75% attendance is required for appearing in end semester exams at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'clubs', 'Clubs > Inertia (dance club) at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'clubs', 'Clubs > Pixel (photography club) at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'clubs', 'Clubs > Qubit (coding club) at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fests', 'Fests > No large cultural events at NIT Manipur. Small events include Flash mob and Regen Hackathon. Major events are Freshers and Farewell.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'laundry', 'Laundry > Washing machine available only in H01 hostel at Rs 50 per kg. Outside washing businesses available. Most students wash their own clothes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'elections', 'Elections > No student elections at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'sports', 'Sports > Available: Cricket, Volleyball, Chess, Kho-Kho, Badminton. Inter-NIT sports competitions and one sports meet per year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'canteen', 'Canteen > One canteen inside the hostel at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'canteen', 'Canteen > 3 small restaurants near campus that belong to NIT Manipur, open 9 AM - 7 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'shops', 'Shops > One stationery shop near campus beside the 3 restaurants.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fines', 'Fines > Rs 2,000 late fine for coming late after holidays at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'fines', 'Fines > Rs 5,000 to Rs 10,000 for indisciplinary actions at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'gym', 'Gym > No gym facility in NIT Manipur college. Nearest private gym is 5 km from campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'health_centre', 'Health Centre > No free medicines available at NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'health_centre', 'Health Centre > Nearby Hospitals: Shija Hospitals (SHRI) at 10.8 km, RIMS at 5.5 km from NIT Manipur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'academics', 'Academics > B.Tech 1st Semester (July-Dec 2025) has 3 groups: Group I (Civil + Mechanical) in LH-18, Group II (Electrical + ECE) in LH-19 New Block, Group III (CSE) in LH-16 New Block.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'academics', 'Academics > Group I and II (Civil, Mechanical, Electrical, ECE) 1st Sem subjects: CS1201 Intro to Computing, EE1201 Basic Electrical, MA1101 Engineering Math-I, EC1201 Basic Electronics, CE1201 Environmental Sustainability, ME1249 Engineering Workshop, IC1192 NCC/NSS.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'academics', 'Academics > Group III (CSE) 1st Sem subjects: CH1101 Engineering Chemistry, ME1101 Engineering Mechanics, MA1101 Engineering Math-I, PH1101 Engineering Physics, HS1101 Communication Skills, ME1149 Engineering Drawing.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'academics', 'Academics > 4th Semester CSE subjects: CS2401 Formal Languages and Automata Theory (FLAT), CS2402 Algorithms (ALGO), CS2403 Computer Organization and Architecture (COA), CS2404 Object Oriented Programming (OOPs), MA2401 Probability.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'academics', 'Academics > 4th Sem CSE Faculty: Dr. Yambem Jina Chanu, Dr. Oinam Bidyapati Chanu, Dr. Yumnam Surajkanta, Dr. Thiyam Susma Devi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Manipur', 'academics', 'Academics > Class timings: 9 AM to 5 PM, Monday to Friday.');
